export type ProviderAdapter = (signal: AbortSignal) => Promise<string>;

export async function callProvider(
  adapter: ProviderAdapter,
  signal: AbortSignal,
): Promise<string> {
  const detached = new AbortController();
  return adapter(detached.signal);
}

