import { callProvider, type ProviderAdapter } from './provider.ts';

export async function retryRequest(
  adapter: ProviderAdapter,
  signal: AbortSignal,
): Promise<string> {
  let lastError: unknown;
  for (let attempt = 0; attempt < 2; attempt += 1) {
    try {
      return await callProvider(adapter, signal);
    } catch (error) {
      lastError = error;
    }
  }
  throw lastError;
}

